/**
 * n8n Code node (JavaScript)
 * - Keeps ALL original fields
 * - Adds the 6 generated_* fields + preview_url
 * - Removes only: prompt_name, prompt_version, config_version, schema_version
 *
 * Assumptions:
 * - item.json.carousel is a JSON string OR already-parsed object
 * - slides_json / hashtags_json may exist as fallbacks (string or array)
 */

function safeJsonParse(maybeJson, fallback = null) {
  if (maybeJson === null || maybeJson === undefined) return fallback;
  if (typeof maybeJson === "object") return maybeJson; // already parsed
  if (typeof maybeJson !== "string") return fallback;

  const s = maybeJson.trim();
  if (!s) return fallback;

  try {
    return JSON.parse(s);
  } catch {
    return fallback;
  }
}

function toJsonString(value, fallback = "[]") {
  try {
    if (value === undefined || value === null) return fallback;
    return JSON.stringify(value);
  } catch {
    return fallback;
  }
}

function firstNonEmpty(...vals) {
  for (const v of vals) {
    if (typeof v === "string" && v.trim()) return v.trim();
  }
  return "";
}

function firstLine(text) {
  if (typeof text !== "string") return "";
  const line = text.split(/\r?\n/).find((l) => l.trim());
  return (line || "").trim();
}

return items.map((item) => {
  const row = item.json ?? {};

  // Parse carousel JSON (preferred)
  const carouselObj = safeJsonParse(row.carousel, null);

  // Fallbacks
  const slidesFallback = safeJsonParse(row.slides_json, []);
  const hashtagsFallback = safeJsonParse(row.hashtags_json, []);

  const slides = Array.isArray(carouselObj?.items)
    ? carouselObj.items
    : (Array.isArray(slidesFallback) ? slidesFallback : []);

  const hashtags = Array.isArray(carouselObj?.hashtags)
    ? carouselObj.hashtags
    : (Array.isArray(hashtagsFallback) ? hashtagsFallback : []);

  const caption = (typeof carouselObj?.caption === "string") ? carouselObj.caption : "";

  const titleFromSlide1 =
    (slides?.[0] && typeof slides[0].headline === "string") ? slides[0].headline : "";

  const generated_title = firstNonEmpty(
    titleFromSlide1,
    typeof carouselObj?.video_title === "string" ? carouselObj.video_title : "",
    typeof carouselObj?.variation_name === "string" ? carouselObj.variation_name : "",
    typeof row.task_id === "string" ? row.task_id : ""
  );

  const generated_hook = firstNonEmpty(
    typeof carouselObj?.hook === "string" ? carouselObj.hook : "",
    firstLine(caption),
    titleFromSlide1
  );

  // Keep everything, add derived fields
  const out = {
    ...row,

    preview_url: row.preview_url ?? "",

    generated_title,
    review_status: "READY",
    generated_hook,
    generated_caption: caption,
    generated_slides_json: toJsonString(slides, "[]"),
    generated_hashtags_json: toJsonString(hashtags, "[]"),
  };

  // Remove ONLY these four from output
  delete out.prompt_name;
  delete out.prompt_version;
  delete out.config_version;
  delete out.schema_version;

  return { json: out };
});

