// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const trim = (s) => String(s ?? "").trim();

function isProbablyVideo(url, assetType, objectPath) {
  const t = trim(assetType).toLowerCase();
  if (["final_video", "merged_video", "scene_clip", "video", "voiceover", "subtitles"].includes(t))
    return true;
  const u = (trim(url) + " " + trim(objectPath)).toLowerCase();
  return /\.(mp4|webm|mov|m4v)(\?|#|$)/i.test(u);
}

const SUPABASE_PUBLIC_BASE = "https://pcdbnzoirwmjefvlmbme.supabase.co";

function publicUrlForRow(r) {
  let url = r.public_url != null ? trim(r.public_url) : "";
  if (!url && r.bucket && r.object_path) {
    const base = SUPABASE_PUBLIC_BASE.replace(/\/$/, "");
    let path = trim(r.object_path);
    if (path.startsWith("/")) path = path.slice(1);
    url = `${base}/storage/v1/object/public/${trim(r.bucket)}/${path}`;
  }
  return url;
}

function taskIdFromStoragePath(pathInBucket) {
  let p = trim(pathInBucket).replace(/\\/g, "/");
  if (!p) return "";
  p = p.split("?")[0];
  if (/^https?:\/\//i.test(p)) {
    try {
      const u = new URL(p);
      p = decodeURIComponent(u.pathname);
    } catch {
      return "";
    }
  }
  p = p.replace(/^\/+/, "");
  const pub = p.match(/(?:^|\/)(?:storage\/v1\/)?object\/public\/[^/]+\/(.+)$/i);
  if (pub) p = pub[1];
  const segs = p.split("/").filter(Boolean);
  if (segs.length < 2) return "";
  return segs[segs.length - 2];
}

function taskIdFromPublicUrl(publicUrl) {
  try {
    const u = new URL(trim(publicUrl));
    return taskIdFromStoragePath(decodeURIComponent(u.pathname));
  } catch {
    return "";
  }
}

const all = $input.all();
let rows = [];
for (const it of all) {
  const j = it.json;
  if (Array.isArray(j)) rows = rows.concat(j);
  else if (Array.isArray(j.body)) rows = rows.concat(j.body);
  else if (Array.isArray(j.data)) rows = rows.concat(j.data);
  else if (j.position != null || j.public_url != null || j.object_path != null) rows.push(j);
}

let taskId = "";
for (const r of rows) {
  const fromObj = taskIdFromStoragePath(r.object_path);
  if (fromObj) {
    taskId = fromObj;
    break;
  }
  const fromUrl = taskIdFromPublicUrl(r.public_url);
  if (fromUrl) {
    taskId = fromUrl;
    break;
  }
}

const urls = [];
for (const r of rows) {
  const url = publicUrlForRow(r);
  if (!url || !/^https?:\/\//i.test(url)) continue;
  if (isProbablyVideo(url, r.asset_type, r.object_path)) continue;
  urls.push(url);
}

const seen = new Set();
const ordered = [];
for (const u of urls) {
  if (seen.has(u)) continue;
  seen.add(u);
  ordered.push(u);
}

return [
  {
    json: {
      task_id: taskId,
      publish_media_urls: ordered,
      publish_media_urls_json: JSON.stringify(ordered),
    },
  },
];

/**
 * VALIDATION / REWORK JOIN (AFTER MERGE APPEND)
 *
 * Input: 3 appended streams (Content_Jobs, Review_Queue, Job_Drafts)
 * Output: one item per job (or per NEEDS_EDIT if you enable the filter), with attached:
 *  - review row (by task_id)
 *  - latest draft row (by task_id, picks highest revision_round/attempt_no/draft_created_at)
 *
 * IMPORTANT:
 * - You SHOULD tag streams with __src before the merge.
 * - If you didn't, this code will still work using heuristics (sheet inference),
 *   but tagging is safer.
 */

const rawItems = $input.all().map(i => i.json);

// ---------- helpers ----------
const s = (v) => (v === null || v === undefined) ? "" : String(v);
const trim = (v) => s(v).trim();

const toInt = (v, def = -1) => {
  const n = parseInt(String(v ?? "").trim(), 10);
  return Number.isFinite(n) ? n : def;
};

const toTime = (v) => {
  const t = Date.parse(String(v ?? "").trim());
  return Number.isFinite(t) ? t : 0;
};

const normTaskId = (obj) => {
  // guard against schema pollution like "task_id " etc
  // (you already have "candidate_id " in your sheet)
  if (obj.task_id !== undefined) return trim(obj.task_id);
  // fallback: scan keys that look like task_id
  const k = Object.keys(obj).find(k => k.trim() === "task_id");
  return k ? trim(obj[k]) : "";
};

const hasAny = (obj, keys) => keys.some(k => obj[k] !== undefined && s(obj[k]).trim() !== "");

const inferSrc = (obj) => {
  // 1) explicit tag (preferred)
  if (obj.__src) return trim(obj.__src);

  // 2) heuristic inference (best-effort)
  // Review_Queue tends to have decision/validator/submit/submitted_at
  if (hasAny(obj, ["decision", "validator", "submit", "submitted_at", "review_status"])) return "review_queue";

  // Job_Drafts tends to have draft_id/draft_created_at/revision_round/attempt_no/prompt_name
  if (hasAny(obj, ["draft_id", "draft_created_at", "revision_round", "attempt_no", "prompt_name", "prompt_version"])) return "job_drafts";

  // Content_Jobs tends to have generated_* fields and/or render_pack_json/template_key/recommended_route
  if (hasAny(obj, ["recommended_route", "generated_caption", "generated_slides_json", "render_pack_json", "template_key"])) return "content_jobs";

  // last resort
  return "unknown";
};

const pickBetterDraft = (a, b) => {
  // Return the "latest" draft between a and b.
  // Priority: higher revision_round, then higher attempt_no, then newer draft_created_at, then newer created_at
  if (!a) return b;
  if (!b) return a;

  const ar = toInt(a.revision_round, -1);
  const br = toInt(b.revision_round, -1);
  if (br !== ar) return br > ar ? b : a;

  const aa = toInt(a.attempt_no, -1);
  const ba = toInt(b.attempt_no, -1);
  if (ba !== aa) return ba > aa ? b : a;

  const at = toTime(a.draft_created_at) || toTime(a.created_at);
  const bt = toTime(b.draft_created_at) || toTime(b.created_at);
  if (bt !== at) return bt > at ? b : a;

  // fallback: prefer non-empty draft_id
  const ad = trim(a.draft_id);
  const bd = trim(b.draft_id);
  if (!!bd !== !!ad) return bd ? b : a;

  return b; // default to later-seen
};

// ---------- split streams ----------
const buckets = {
  content_jobs: [],
  review_queue: [],
  job_drafts: [],
  unknown: [],
};

for (const obj of rawItems) {
  const src = inferSrc(obj);
  (buckets[src] || buckets.unknown).push(obj);
}

// ---------- index by task_id ----------
const reviewByTask = new Map(); // one per task (latest submitted_at wins)
for (const r of buckets.review_queue) {
  const taskId = normTaskId(r);
  if (!taskId) continue;

  const prev = reviewByTask.get(taskId);
  if (!prev) {
    reviewByTask.set(taskId, r);
    continue;
  }

  const pt = toTime(prev.submitted_at) || toTime(prev.synced_at) || toTime(prev.created_at);
  const rt = toTime(r.submitted_at) || toTime(r.synced_at) || toTime(r.created_at);
  reviewByTask.set(taskId, rt >= pt ? r : prev);
}

const draftByTask = new Map(); // best/latest draft per task
for (const d of buckets.job_drafts) {
  const taskId = normTaskId(d);
  if (!taskId) continue;

  const prev = draftByTask.get(taskId);
  draftByTask.set(taskId, pickBetterDraft(prev, d));
}

// ---------- output selection ----------
const jobs = buckets.content_jobs;

// Toggle this to only output NEEDS_EDIT jobs (useful for the rework handler)
const ONLY_NEEDS_EDIT = false;

// Decide NEEDS_EDIT from review decision primarily; fallback to recommended_route if you insist
const isNeedsEdit = (job, review) => {
  const dec = trim(review?.decision).toUpperCase();
  if (dec === "NEEDS_EDIT") return true;

  // fallback: sometimes you store it in review_status (not ideal)
  const rs = trim(review?.review_status).toUpperCase();
  if (rs === "NEEDS_EDIT") return true;

  // last resort fallback: recommended_route
  const rr = trim(job?.recommended_route).toUpperCase();
  if (rr === "NEEDS_EDIT") return true;

  return false;
};

// ---------- build rows ----------
const out = [];
for (const j of jobs) {
  const taskId = normTaskId(j);
  if (!taskId) continue;

  const review = reviewByTask.get(taskId) || null;
  const draft = draftByTask.get(taskId) || null;

  if (ONLY_NEEDS_EDIT && !isNeedsEdit(j, review)) continue;

  out.push({
    json: {
      // keep job as top-level for easy mapping back to Content_Jobs
      ...j,

      // attach objects for downstream steps
      review,
      draft,

      // join debug (super useful while you wire this)
      _join_debug: {
        task_id: taskId,
        src_counts: {
          content_jobs: buckets.content_jobs.length,
          review_queue: buckets.review_queue.length,
          job_drafts: buckets.job_drafts.length,
          unknown: buckets.unknown.length,
        },
        has_review: !!review,
        has_draft: !!draft,
        decision: trim(review?.decision),
        recommended_route: trim(j?.recommended_route),
      },
    }
  });
}

// If you got 0 output, emit one debug row instead of silent failure
if (out.length === 0) {
  return [{
    json: {
      error: "JOIN_PRODUCED_ZERO_ROWS",
      hint: "Check that your merge includes Content_Jobs rows (and that inferSrc isn't misclassifying). Consider adding __src tags before merge.",
      src_counts: {
        content_jobs: buckets.content_jobs.length,
        review_queue: buckets.review_queue.length,
        job_drafts: buckets.job_drafts.length,
        unknown: buckets.unknown.length,
      },
      sample_unknown: buckets.unknown[0] || null,
    }
  }];
}

return out;

/**
 * CAF_REWORK_ORCHESTRATOR
 * Input: appended rows from Review Queue, Content_Jobs, Job_Drafts
 * Output: one normalized rework job per NEEDS_EDIT review row
 */

const rows = $input.all().map(i => i.json);

const toInt = (v, d = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};

const toStr = (v) => v == null ? '' : String(v);

const parseMaybeJson = (v, fallback = null) => {
  if (v == null || v === '') return fallback;
  if (typeof v === 'object') return v;
  try { return JSON.parse(v); } catch { return fallback; }
};

const nonEmpty = (...vals) => vals.find(v => v !== undefined && v !== null && String(v).trim() !== '');

const nowIso = new Date().toISOString();

const inferSrc = (row) => {
  if (row.__src) return row.__src;
  if ('decision' in row || 'review_status' in row || 'final_caption_override' in row) return 'review_queue';
  if ('draft_id' in row && ('attempt_no' in row || 'generation_reason' in row || 'generated_caption' in row)) return 'job_drafts';
  if ('carousel' in row || 'render_pack_json' in row || 'video_url' in row || 'spoken_script' in row) return 'content_jobs';
  return 'unknown';
};

const compareDraft = (a, b) => {
  const aRev = toInt(a.revision_round, 0);
  const bRev = toInt(b.revision_round, 0);
  if (aRev !== bRev) return aRev - bRev;

  const aAttempt = toInt(a.attempt_no, 0);
  const bAttempt = toInt(b.attempt_no, 0);
  if (aAttempt !== bAttempt) return aAttempt - bAttempt;

  const aTs = Date.parse(nonEmpty(a.draft_created_at, a.created_at, '1970-01-01T00:00:00Z')) || 0;
  const bTs = Date.parse(nonEmpty(b.draft_created_at, b.created_at, '1970-01-01T00:00:00Z')) || 0;
  if (aTs !== bTs) return aTs - bTs;

  return toStr(a.draft_id).localeCompare(toStr(b.draft_id));
};

const extractRootTaskId = (taskId) => toStr(taskId).replace(/__v\d+$/i, '');
const extractVersionNum = (value) => {
  const m = toStr(value).match(/(?:__v|_v)(\d+)$/i);
  return m ? Number(m[1]) : 1;
};

const nextVersionedTaskId = (taskId, nextVersion) => {
  const root = extractRootTaskId(taskId);
  return `${root}__v${nextVersion}`;
};

const nextVersionedCandidateId = (candidateId, nextVersion) => {
  const s = toStr(candidateId);
  const root = s.replace(/_v\d+$/i, '');
  return `${root}_v${nextVersion}`;
};

const reviewByTask = new Map();
const jobsByTask = new Map();
const latestDraftByTask = new Map();

for (const row of rows) {
  const src = inferSrc(row);
  const taskId = toStr(row.task_id).trim();
  if (!taskId) continue;

  if (src === 'review_queue') {
    const existing = reviewByTask.get(taskId);
    if (!existing) {
      reviewByTask.set(taskId, row);
    } else {
      const existingTs = Date.parse(nonEmpty(existing.synced_at, existing.submitted_at, existing.generated_at, '1970-01-01T00:00:00Z')) || 0;
      const rowTs = Date.parse(nonEmpty(row.synced_at, row.submitted_at, row.generated_at, '1970-01-01T00:00:00Z')) || 0;
      if (rowTs >= existingTs) reviewByTask.set(taskId, row);
    }
    continue;
  }

  if (src === 'content_jobs') {
    jobsByTask.set(taskId, row);
    continue;
  }

  if (src === 'job_drafts') {
    const prev = latestDraftByTask.get(taskId);
    if (!prev || compareDraft(prev, row) < 0) latestDraftByTask.set(taskId, row);
  }
}

const inferEditScope = (review, latestDraft, job) => {
  const scopes = [];
  const push = (v) => { if (v && !scopes.includes(v)) scopes.push(v); };

  if (toStr(review.final_title_override).trim()) push('title');
  if (toStr(review.final_hook_override).trim()) push('hook');
  if (toStr(review.final_caption_override).trim()) push('caption');
  if (toStr(review.final_slides_json_override).trim()) push(job.flow_type === 'FLOW_VIDEO' ? 'script' : 'slides');

  const rawTags = parseMaybeJson(review.rejection_tags, []);
  const tags = Array.isArray(rawTags)
    ? rawTags.map(x => toStr(x).toLowerCase())
    : toStr(review.rejection_tags).toLowerCase().split(/[,\n;]+/).map(s => s.trim()).filter(Boolean);

  const notes = `${toStr(review.notes)} ${toStr(review.generation_notes)}`.toLowerCase();

  const mapping = [
    ['hook', /(hook|opener|opening|first line|headline)/],
    ['caption', /(caption|description)/],
    ['cta', /(cta|call to action)/],
    ['slides', /(slide|slides|carousel|too long|verbose)/],
    ['script', /(script|voiceover|spoken|dialogue|beats|scene)/],
    ['visual_direction', /(visual|camera|editing|shot|scene|render)/],
    ['title', /(title)/],
  ];

  for (const [scope, rx] of mapping) {
    if (tags.some(t => rx.test(t)) || rx.test(notes)) push(scope);
  }

  if (!scopes.length) {
    if (toStr(job.flow_type).includes('VIDEO')) push('script');
    else push('slides');
  }

  return scopes;
};

const inferMode = (review, scopes) => {
  const hasOverrides = [
    review.final_title_override,
    review.final_hook_override,
    review.final_caption_override,
    review.final_slides_json_override,
  ].some(v => toStr(v).trim());

  if (hasOverrides) return 'OVERRIDE_ONLY';

  const tags = toStr(review.rejection_tags).toLowerCase();
  const notes = toStr(review.notes).toLowerCase();
  const fullSignals = /(redo|full|rework|new angle|wrong angle|wrong direction|start over|generic|tone off|rebuild|entire|whole)/;
  if (fullSignals.test(`${tags} ${notes}`)) return 'FULL_REWORK';

  if (scopes.length >= 3) return 'FULL_REWORK';
  return 'PARTIAL_REWRITE';
};

const out = [];

for (const [taskId, review] of reviewByTask.entries()) {
  const decision = toStr(review.decision || review.review_status || '').trim().toUpperCase();
  if (decision !== 'NEEDS_EDIT') continue;

  const job = jobsByTask.get(taskId) || {};
  const latestDraft = latestDraftByTask.get(taskId) || {};
  const flowType = nonEmpty(review.flow_type, job.flow_type, latestDraft.flow_type, 'FLOW_CAROUSEL');
  const platform = nonEmpty(review.platform, job.platform, latestDraft.platform, 'Instagram');

  const currentCandidateId = nonEmpty(review.candidate_id, job.candidate_id, latestDraft.candidate_id, '');
  const currentVersion = Math.max(
    extractVersionNum(taskId),
    extractVersionNum(currentCandidateId),
    toInt(review.revision_round, 0) || 1,
    toInt(latestDraft.revision_round, 0) || 1,
    toInt(job.revision_round, 0) || 1
  );
  const nextVersion = currentVersion + 1;
  const taskRootId = extractRootTaskId(taskId);
  const nextTaskId = nextVersionedTaskId(taskId, nextVersion);
  const nextCandidateId = nextVersionedCandidateId(currentCandidateId || taskRootId.replace(/__/g, '_'), nextVersion);
  const nextDraftId = `d_${Math.random().toString(36).slice(2, 12)}`;

  const sourceSnapshot = {
    generated_title: nonEmpty(review.generated_title, latestDraft.generated_title, ''),
    generated_hook: nonEmpty(review.generated_hook, latestDraft.generated_hook, job.hook, ''),
    generated_caption: nonEmpty(review.generated_caption, latestDraft.generated_caption, job.caption, ''),
    generated_slides_json: nonEmpty(review.generated_slides_json, latestDraft.generated_slides_json, job.slides_json, ''),
    generated_hashtags_json: nonEmpty(review.generated_hashtags_json, latestDraft.generated_hashtags_json, job.hashtags_json, ''),
    generated_render_json: nonEmpty(review.generated_render_json, latestDraft.generated_render_json, job.render_pack_json, ''),
    preview_url: nonEmpty(review.preview_url, latestDraft.preview_url, ''),
    spoken_script: nonEmpty(review.spoken_script, latestDraft.spoken_script, job.spoken_script, ''),
    cta: nonEmpty(review.cta, latestDraft.cta, job.cta, ''),
    disclaimer: nonEmpty(review.disclaimer, latestDraft.disclaimer, job.disclaimer, ''),
    beats_json: nonEmpty(review.beats_json, latestDraft.beats_json, job.beats_json, ''),
    dialogue_json: nonEmpty(review.dialogue_json, latestDraft.dialogue_json, job.dialogue_json, ''),
    on_screen_text_json: nonEmpty(review.on_screen_text_json, latestDraft.on_screen_text_json, job.on_screen_text_json, ''),
    visual_direction_json: nonEmpty(review.visual_direction_json, latestDraft.visual_direction_json, job.visual_direction_json, ''),
  };

  const editScope = inferEditScope(review, latestDraft, job);
  const reworkMode = inferMode(review, editScope);

  out.push({
    json: {
      task_id: taskId,
      task_root_id: taskRootId,
      task_id_next: nextTaskId,
      candidate_id: currentCandidateId,
      parent_candidate_id: currentCandidateId,
      candidate_id_next: nextCandidateId,
      latest_draft_id: nonEmpty(review.draft_id, latestDraft.draft_id, job.draft_id, ''),
      draft_id_next: nextDraftId,
      revision_round_current: Math.max(toInt(review.revision_round, 0), toInt(latestDraft.revision_round, 0), toInt(job.revision_round, 0)),
      revision_round_next: nextVersion,
      attempt_no_next: 1,
      project: nonEmpty(review.project, job.project, latestDraft.project, ''),
      run_id: nonEmpty(review.run_id, job.run_id, latestDraft.run_id, ''),
      signal_pack_run_id: nonEmpty(review.signal_pack_run_id, job.signal_pack_run_id, latestDraft.signal_pack_run_id, ''),
      platform,
      flow_type: flowType,
      variation_name: `v${nextVersion}`,
      rework_mode: reworkMode,
      edit_scope: editScope,
      decision: 'NEEDS_EDIT',
      review_feedback: {
        rejection_tags: parseMaybeJson(review.rejection_tags, review.rejection_tags || []),
        notes: toStr(review.notes),
        validator: nonEmpty(review.validator, 'human'),
      },
      human_overrides: {
        final_title_override: toStr(review.final_title_override),
        final_hook_override: toStr(review.final_hook_override),
        final_caption_override: toStr(review.final_caption_override),
        final_slides_json_override: toStr(review.final_slides_json_override),
      },
      preserve: {
        template_key: nonEmpty(review.template_key, job.template_key, latestDraft.template_key, ''),
        preview_url: sourceSnapshot.preview_url,
        keep_visual_direction: true,
        render_provider: nonEmpty(review.render_provider, job.render_provider, latestDraft.render_provider, ''),
      },
      source_snapshot: sourceSnapshot,
      review: review,
      job: job,
      latest_draft: latestDraft,
      _generated_at: nowIso
    }
  });
}

return out;

const item = $json;
const review = item.review || {};
const job = item.job || {};
