const snapshot = item.source_snapshot || {};
const overrides = item.human_overrides || {};
const nowIso = item._generated_at || new Date().toISOString();

const pick = (...vals) => vals.find(v => v !== undefined && v !== null && String(v).trim() !== '');
const jsonString = (v) => typeof v === 'string' ? v : JSON.stringify(v ?? null);

const newHook = pick(overrides.final_hook_override, snapshot.generated_hook, job.hook, '');
