const item = $json;
const brief = item.rework_brief || {};
const source = item.source_snapshot || {};
const job = item.job || {};

const parseMaybeJson = (v, fallback = null) => {
  if (v == null || v === '') return fallback;
  if (typeof v === 'object') return v;
  try { return JSON.parse(v); } catch { return fallback; }
};
const pick = (...vals) => vals.find(v => v !== undefined && v !== null && String(v).trim() !== '');

let generatedTitle = pick(item.generated_title, item.title, item.output_json?.title, item.output?.title, source.generated_title, '');
let generatedHook = pick(item.generated_hook, item.hook, item.output_json?.hook, item.output?.hook, source.generated_hook, '');
let generatedCaption = pick(item.generated_caption, item.caption, item.output_json?.caption, item.output?.caption, source.generated_caption, '');
