let onScreenTextJson = pick(item.on_screen_text_json, item.output_json?.on_screen_text_json, source.on_screen_text_json, job.on_screen_text_json, '');
let visualDirectionJson = pick(item.visual_direction_json, item.output_json?.visual_direction_json, source.visual_direction_json, job.visual_direction_json, '');

if (typeof generatedSlidesJson !== 'string' && generatedSlidesJson != null) generatedSlidesJson = JSON.stringify(generatedSlidesJson);
if (typeof generatedHashtagsJson !== 'string' && generatedHashtagsJson != null) generatedHashtagsJson = JSON.stringify(generatedHashtagsJson);
if (typeof generatedRenderJson !== 'string' && generatedRenderJson != null) generatedRenderJson = JSON.stringify(generatedRenderJson);
if (typeof beatsJson !== 'string' && beatsJson != null) beatsJson = JSON.stringify(beatsJson);
if (typeof dialogueJson !== 'string' && dialogueJson != null) dialogueJson = JSON.stringify(dialogueJson);
if (typeof onScreenTextJson !== 'string' && onScreenTextJson != null) onScreenTextJson = JSON.stringify(onScreenTextJson);
if (typeof visualDirectionJson !== 'string' && visualDirectionJson != null) visualDirectionJson = JSON.stringify(visualDirectionJson);

return [{
