      candidate_id_original: item.candidate_id,
      candidate_id_next: item.candidate_id_next,
      draft_id_next: item.draft_id_next,
      revision_round_next: item.revision_round_next,
      generated_title: generatedTitle,
      generated_hook: generatedHook,
      generated_caption: generatedCaption,
      generated_slides_json: generatedSlidesJson,
      generated_hashtags_json: generatedHashtagsJson,
      generated_render_json: generatedRenderJson,
      preview_url: pick(item.preview_url, source.preview_url, ''),
      spoken_script: spokenScript,
      cta,
      disclaimer,
      beats_json: beatsJson,
      dialogue_json: dialogueJson,
      on_screen_text_json: onScreenTextJson,
      visual_direction_json: visualDirectionJson,
      base_record: item
    }
  }
}];
